arguments.argument:
if global.gamePaused=false
{
  if type=1
  {
    if bGoDown=1
    {
      y+=2
      if y>=-78 {bGoDown=0} //216-286
    }
    else
    {
      y-=2
      if y<=-276 {bGoDown=1} //12-286
    }
  }
  else if type=2
  {
    if myMaster.bGoDown=1
    {
      y+=2
    }
    else
    {
      y-=2
    }
  }
}
